// Extraer los response del JSON
const responses = $json.message.content.response;

// Tomar máximo 3 y devolver solo los IDs
const top3 = responses.slice(0, 3);

return top3.map(doc => {
    return {
        id: doc.id
    };
});

const items = $input.all();
const outputs = Array.from(items, item => item.json?.output || '');
return [
  {
    json: {
      unified_response: outputs.filter(output => output).join('\n\n---RESPUESTA SIGUIENTE---\n\n'),
      total_responses: outputs.filter(output => output).length,
      individual_outputs: outputs.filter(output => output)
    },
    pairedItem: items.map((_, index) => ({ item: index }))
  }
];

const items = $input.all();

const pdfsTotales = [];
const agentesTotales = new Set();
const nodosProcesadosTotales = new Set();
const nodosIgnoradosTotales = new Set();

for (const item of items) {
  let rawOutput = item.json.output;
  let parsed = {};

  // Parsear 'output' si viene como string
  if (typeof rawOutput === 'string') {
    try {
      parsed = JSON.parse(rawOutput);
    } catch (e) {
      continue;
    }
  } else if (typeof rawOutput === 'object') {
    parsed = rawOutput;
  }

  // PDFs
  if (Array.isArray(parsed.pdfs_relevantes)) {
    pdfsTotales.push(...parsed.pdfs_relevantes);
  }

  // Agentes (si vinieran)
  if (Array.isArray(parsed.agentes_activados)) {
    parsed.agentes_activados.forEach(a => agentesTotales.add(a));
  }

  // Debug
  const debug = item.json.debug;
  if (typeof debug === 'string') {
    try {
      const dbg = JSON.parse(debug);
      (dbg.nodosProcesados || []).forEach(n => nodosProcesadosTotales.add(n));
      (dbg.nodosIgnorados || []).forEach(n => nodosIgnoradosTotales.add(n));
    } catch (e) {}
  } else if (typeof debug === 'object') {
    (debug?.nodosProcesados || []).forEach(n => nodosProcesadosTotales.add(n));
    (debug?.nodosIgnorados || []).forEach(n => nodosIgnoradosTotales.add(n));
  }
}

// Filtrar y ordenar los PDF por relevancia
const relevanciaMinima = 50;
const pdfsFiltrados = pdfsTotales
  .filter(pdf => pdf.relevancia >= relevanciaMinima)
  .sort((a, b) => b.relevancia - a.relevancia);

// Crear mensaje para OpenAI
const resumen = pdfsFiltrados.map(pdf =>
  `• ${pdf.nombre} (${pdf.relevancia}): ${pdf.razon}`
).join('\n');

return [
  {
    json: {
      output: {
        pdfs_relevantes: pdfsFiltrados,
        agentes_activados: Array.from(agentesTotales),
        total_documentos: pdfsFiltrados.length
      },
      debug: {
        nodosProcesados: Array.from(nodosProcesadosTotales),
        nodosIgnorados: Array.from(nodosIgnoradosTotales)
      },
      messages: [
        {
          role: "system",
          content: "You are a legal assistant specialized in municipal regulations of Madrid. Be clear, concise, and accurate. Do not hallucinate information."
        },
        {
          role: "user",
          content: `Summarize the following documents related to food street vending in public parks in Madrid:\n\n${resumen}`
        }
      ]
    }
  }
];

